const prev = $('Extrair Dados').first().json;
const resp = $input.item.json;

let text = '';

if (resp.protocolo) {
  const statusEmoji = {
    'RECEBIDA': '📥',
    'EM_ANALISE': '🔍',
    'VALIDADA': '✅',
    'EM_RESOLUCAO': '🔧',
    'RESOLVIDA': '🎉',
    'ARQUIVADA': '📦',
    'REJEITADA': '❌'
  };
  const emoji = statusEmoji[resp.status] || '📋';
  const statusText = (resp.status || '').replace(/_/g, ' ');
  const data = resp.dataRegistro ? resp.dataRegistro.substring(0, 10) : '—';
  const desc = resp.descricao ? (resp.descricao.length > 80 ? resp.descricao.substring(0, 80) + '...' : resp.descricao) : '—';

  text = `🔍 *Status do Protocolo ${resp.protocolo}*\n\n${emoji} Status: *${statusText}*\n🏷️ Categoria: ${resp.categoriaNome || '—'}\n📝 ${desc}\n📅 Registrado em: ${data}`;
} else {
  text = `⚠️ Protocolo *${prev.text}* não encontrado.\n\nVerifique o número e tente novamente.\nFormato correto: RPT-2026-00001`;
}

return { phone: prev.phone, text };

